import React, { useMemo } from "react";
import { Container, Row, Col } from "react-bootstrap";
import Particle from "../Particle";
import { useInViewOnce } from "../../hooks/useInViewOnce";
import { useTranslation } from "react-i18next";
import { certifications } from "../../data/certifications";

function sortByYearDesc(items) {
  return [...items].sort((a, b) => (b.year ?? 0) - (a.year ?? 0));
}

export default function Certifications() {
  const header = useInViewOnce();
  const earnedRef = useInViewOnce();
  const plannedRef = useInViewOnce();
  const { t, i18n } = useTranslation();

  const isFr = i18n.language?.toLowerCase().startsWith("fr");

  const earned = useMemo(() => sortByYearDesc(certifications.earned ?? []), []);
  const planned = useMemo(() => sortByYearDesc(certifications.planned ?? []), []);

  const renderItem = (c) => {
    const title = isFr ? (c.title_fr ?? c.title) : c.title;
    const issuer = isFr ? (c.issuer_fr ?? c.issuer) : c.issuer;
    return (
      <div key={c.id} className="cert-timeline-item">
        <div className="cert-timeline-marker" aria-hidden="true" />
        <div className="cert-timeline-content">
          <div className="cert-timeline-top">
            <span className="cert-year">{c.year}</span>
          </div>
          <div className="cert-title">{title}</div>
          <div className="cert-issuer">{issuer}</div>
        </div>
      </div>
    );
  };

  return (
    <Container fluid className="cert-section">
      <Particle />
      <Container>
        <div
          ref={header.ref}
          className={`cert-header section-card reveal ${header.isInView ? "is-visible" : ""}`}
        >
          <div className="section-header">
            <h1 className="section-title">
              {t("certs.title_prefix")} <span className="purple">{t("certs.title_highlight")}</span>
            </h1>
            <p className="section-subtitle">{t("certs.subtitle")}</p>
          </div>
        </div>

        <Row className="g-4">
          <Col md={6}>
            <div
              ref={earnedRef.ref}
              className={`section-card reveal ${earnedRef.isInView ? "is-visible" : ""}`}
            >
              <div className="section-header">
                <h2 className="section-title">
                  <span className="purple">{t("certs.earned_title")}</span>
                </h2>
                <p className="section-subtitle">{t("certs.earned_subtitle")}</p>
              </div>
              <div className="section-divider" />
              <div className="cert-timeline">
                {earned.length ? earned.map(renderItem) : <div className="cert-empty">{t("certs.empty")}</div>}
              </div>
            </div>
          </Col>

          <Col md={6}>
            <div
              ref={plannedRef.ref}
              className={`section-card reveal ${plannedRef.isInView ? "is-visible" : ""}`}
            >
              <div className="section-header">
                <h2 className="section-title">
                  <span className="purple">{t("certs.planned_title")}</span>
                </h2>
                <p className="section-subtitle">{t("certs.planned_subtitle")}</p>
              </div>
              <div className="section-divider" />
              <div className="cert-timeline">
                {planned.length ? planned.map(renderItem) : <div className="cert-empty">{t("certs.empty")}</div>}
              </div>
            </div>
          </Col>
        </Row>
      </Container>
    </Container>
  );
}

